INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (100211, 0, 0, "うん、これでいいと思う。\n傷はきれいに塞がったけど、\nまだどこか痛んだりするかな？", 1, 20022, 10, 11, 1, 1200220005, 0);
INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (0, "", "", "", "", 20022, "", 91, "", 1200220006, "");
