INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (104411, 0, 0, "そろそろ野営の準備を始めねばな。\n食料は現地調達するしかないが、\n獣を狩るか、野草を採るか……", 1, 20132, 10, 11, 1, 1201320005, 0);
INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (0, "", "", "", "", 20132, "", 91, "", 1201320006, "");
