INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (100711, 0, 0, "え～！？　そんなの食べたくないの！\nミヤコは三食プリンがいいの～！\nプリンを現地調達するの～！", 1, 20132, 10, 11, 1, 1201320010, 0);
INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (0, "", "", "", "", 20132, "", 91, "", 1201320011, "");
