INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (101611, 0, 0, "ねねね！\nみんなで記念撮影しよ？\nあとで見返したら絶対エモいっしょ！", 1, 20162, 10, 11, 1, 1201620005, 0);
INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (0, "", "", "", "", 20162, "", 91, "", 1201620006, "");
