INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES ("vo_travel_talk", "", "", "vo_travel_talk_20018_02", 0, 20182, 0, 21, "", 1201820011, "");
INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (118011, 0, 0, "……それに、手ぶらで帰ったとなると\n秘書にまた小言を言われそうですし。\nあの子がグゥの音も出なくなるくらい\n稼いで稼いで稼ぎますわよ～っ！", 1, 20182, 10, 11, 1, 1201820012, 0);
INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (0, "", "", "", "", 20182, "", 91, "", 1201820013, "");
