INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (106111, 0, 0, "よーし！　ネネカと一緒に冒険だ！\nせっかくだし、何か悪いことするか？\n七冠とやれば派手になりそうだしさ！", 1, 20192, 10, 11, 1, 1201920005, 0);
INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (0, "", "", "", "", 20192, "", 91, "", 1201920006, "");
