INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (106911, 0, "", "travel_topdrama_r_2000_kaiser_talk_arm_crossed_in", "travel_topdrama_r_2000_kaiser_talk_arm_crossed_loop", 20282, 0, 3, 1, 1202820008, 0.2);
INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES ("vo_travel_talk", "", "", "vo_travel_talk_20028_01", 0, 20282, 0, 21, "", 1202820009, "");
INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (106911, 0, 0, "あなたの能天気な物言い、はらわたが\n煮え返るほど不快だわ。この期に及んで\n冒険ですって……？　ふざけないで。", 1, 20282, 10, 11, 1, 1202820010, 0);
